    // for any existing edge (a, b) with weight w(a, b), d(a) + d(b) = w(a, b) (mod 2).
    // (This means d(a) XOR d(b) = w(a, b)).
    // This is the condition for the graph to be bipartite if all weights were 1.

    // When weights are 0 or 1, the condition that all cycles have even weight 
    // is equivalent to the graph being "balanced" with respect to edge parities.
    // This means there exists an assignment of parity values p[i] (0 or 1) to each node i,
    // such that for every existing edge (u, v) with weight w, p[u] XOR p[v] = w.

    // If we add a new edge (u, v) with weight w, the new graph satisfies the condition 
    // if and only if the existing potential function p can be consistently extended:
    // p[u] XOR p[v] must equal w.
    // If p[u] XOR p[v] == w, then adding the edge maintains the property because any new cycle 
    // formed must satisfy the parity condition based on the existing structure.

    // We can use a Disjoint Set Union (DSU) structure augmented to track this parity difference.
    // For each node i, we will store:
    // 1. parent[i]: The parent of i in the DSU tree.
    // 2. diff[i]: The XOR sum of weights on the path from i to parent[i].
    //    Specifically, diff[i] = (p[i] XOR p[parent[i]]).

    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] stores the parity of the path weight from i to parent[i]
    const diff = Array(n).fill(0);
    let addedEdgesCount = 0;

    /**
     * Finds the root of node i and performs path compression, updating diff accordingly.
     * Returns [root, parity_from_i_to_root].
     */
    function find(i) {
        if (parent[i] === i) {
            return [i, 0]; // Parity from i to itself is 0
        }

        const [root, rootDiff] = find(parent[i]);

        // Update path: i -> parent[i] -> root
        // New diff[i] should be (old diff[i]) XOR (diff from old parent to root)
        diff[i] = diff[i] ^ rootDiff;
        parent[i] = root;

        return [root, diff[i]];
    }

    /**
     * Tries to unite sets containing u and v with edge weight w.
     * Returns true if the edge is added, false otherwise.
     */
    function union(u, v, w) {
        const [rootU, diffU] = find(u);
        const [rootV, diffV] = find(v);

        if (rootU !== rootV) {
            // Not connected, safe to add the edge.
            // We merge rootV into rootU (arbitrarily).
            parent[rootV] = rootU;

            // We need to set diff[rootV] such that:
            // p[rootV] XOR p[rootU] = diff[rootV]

            // We know:
            // 1. p[u] XOR p[rootU] = diffU  => p[rootU] = p[u] XOR diffU
            // 2. p[v] XOR p[rootV] = diffV  => p[rootV] = p[v] XOR diffV
            // 3. p[u] XOR p[v] = w          => p[v] = p[u] XOR w

            // Substitute (3) into (2):
            // p[rootV] = (p[u] XOR w) XOR diffV

            // We want p[rootV] XOR p[rootU]
            // = ((p[u] XOR w) XOR diffV) XOR (p[u] XOR diffU)
            // = (p[u] XOR p[u]) XOR w XOR diffV XOR diffU
            // = 0 XOR w XOR diffV XOR diffU

            diff[rootV] = diffU ^ w ^ diffV;

            return true;
        } else {
            // Already connected. Check for consistency (cycle creation).
            // The path from u to v through the existing structure has parity:
            // Path_uv_parity = (p[u] XOR p[rootU]) XOR (p[v] XOR p[rootU])
            // Path_uv_parity = diffU XOR diffV

            // The new edge (u, v) has weight w. 
            // If we add it, the cycle formed has weight: (diffU XOR diffV) XOR w.
            // For the property to hold, this cycle weight must be EVEN (i.e., 0 mod 2).
            // (diffU XOR diffV) XOR w == 0
            // <=> w == diffU XOR diffV

            if (w === (diffU ^ diffV)) {
                // Consistent, the cycle has even weight. Add the edge conceptually.
                return true;
            } else {
                // Inconsistent, the cycle has odd weight. Do not add the edge.
                return false;
            }
        }
    }

    for (const [u, v, w] of edges) {
        if (union(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}
